// 三载体一致:纯 JS,clone 避免污染同页其他 Decimal 使用者
import Decimal from 'https://cdn.jsdelivr.net/npm/decimal.js@10/+esm';
const D = Decimal.clone({ precision: data.precision ?? 20, rounding: data.rounding ?? Decimal.ROUND_HALF_UP });
let result = new D(data.value);
for (const step of data.operations ?? []) result = result[step.op](step.operand);
if (data.decimal_places !== undefined) result = result.toDecimalPlaces(data.decimal_places);
const output = result.toString();
